  def _fmt_number(val: str) -> str:
          """
          Format numeric values for natural language output.
          - Remove surrounding commas.
          - Strip trailing “.0” for integers.
          - Do **not** insert thousands separators (commas) because reference
            sentences use plain numbers (e.g., “4100” not “4,100”).
          """
          try:
              num = float(val.replace(",", ""))
              if num.is_integer():
                  num = int(num)
              return str(num)
          except Exception:
              return val
